import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{r as p,o as e,c as t,d as o,a as n,b as c,e as l}from"./app-0014a839.js";const i="/408CSFamily/assets/稀疏矩阵的存储变换-64626011.png",u={},r=n("h1",{id:"栈vs队列补充",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#栈vs队列补充","aria-hidden":"true"},"#"),c(" 栈VS队列补充")],-1),d=n("blockquote",null,[n("p",null,"Tips: 这里不会做过多文字介绍相关应用，具体需要自己看书、查资料揣摩")],-1),k=l(`<h2 id="栈的应用" tabindex="-1"><a class="header-anchor" href="#栈的应用" aria-hidden="true">#</a> 栈的应用</h2><ul><li>括号匹配</li><li>表达式求值</li></ul><blockquote><p>表达式求值是程序设计语言编译中一个最基本的问题，类似有前缀、中缀、后缀表达式转换等典型问题。</p></blockquote><ul><li>递归</li></ul><p>这里重点总结下递归，递归非常重要，是一种很经典的程序设计方法</p><blockquote><p>递归的简单定义： 如果在一个函数、过程或数据结构的定义中又应用了自身，那么这个函数、过程或者数据结构称为递归定义的，简称递归。</p></blockquote><p>递归通常把一个大型的复杂问题，层层转化为一个与原问题相似的规模较小的问题来求解。</p><p><strong>递归策略只需要少量的代码就可以描述出解题过程所需要的多次重复的计算，很大程度上减少了程序的代码量，当时通常情况下，递归的效率并不是很高</strong></p><p>经典的斐波拉切数列，可以用递归来实现：</p><div class="language-cpp line-numbers-mode" data-ext="cpp"><pre class="language-cpp"><code>
<span class="token comment">// 定义递归函数，实现斐波拉切数列</span>

<span class="token keyword">int</span> <span class="token function">Fibonacci</span><span class="token punctuation">(</span>n<span class="token punctuation">)</span><span class="token punctuation">{</span>
    <span class="token keyword">if</span><span class="token punctuation">(</span>n<span class="token operator">==</span><span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
        <span class="token keyword">return</span> <span class="token number">0</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span><span class="token keyword">else</span> <span class="token keyword">if</span><span class="token punctuation">(</span>n<span class="token operator">==</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
        <span class="token keyword">return</span> <span class="token number">1</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span><span class="token keyword">else</span><span class="token punctuation">{</span>
        <span class="token comment">// 调用Fibonacci函数，进行递归</span>
        <span class="token keyword">return</span> <span class="token function">Fibonacci</span><span class="token punctuation">(</span>n<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token operator">+</span><span class="token function">Fib</span><span class="token punctuation">(</span>n<span class="token operator">-</span><span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>


</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面很基础的代码，是分<code>n=0</code>和<code>n=1</code>的情况，先进行过滤，其他情况下则进行递归，其实在日常开发中，经常会有简化的函数封装</p><div class="language-cpp line-numbers-mode" data-ext="cpp"><pre class="language-cpp"><code>
<span class="token comment">// 定义递归函数，实现斐波拉切数列</span>

<span class="token keyword">int</span> <span class="token function">Fibonacci</span><span class="token punctuation">(</span>n<span class="token punctuation">)</span><span class="token punctuation">{</span>
    <span class="token keyword">if</span><span class="token punctuation">(</span>n<span class="token operator">&lt;</span><span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
        <span class="token keyword">return</span> n<span class="token punctuation">;</span>
    <span class="token punctuation">}</span><span class="token keyword">else</span><span class="token punctuation">{</span>
        <span class="token comment">// 调用Fibonacci函数，进行递归</span>
        <span class="token keyword">return</span> <span class="token function">Fibonacci</span><span class="token punctuation">(</span>n<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token operator">+</span><span class="token function">Fib</span><span class="token punctuation">(</span>n<span class="token operator">-</span><span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面的简化，则需要程序考虑变量n是整数。</p><p>当然，前面有说道：<strong>通常情况下，递归的效率并不搞</strong>，主要原因就是递归通过返回调用自己本身，导致往往时间复杂度较高。</p><p>可以采用空间换时间的思路，来降低算法的时间复杂度</p><div class="language-cpp line-numbers-mode" data-ext="cpp"><pre class="language-cpp"><code><span class="token comment">// 使用非递归实现</span>
<span class="token keyword">int</span> <span class="token function">Fibonacci</span><span class="token punctuation">(</span><span class="token keyword">int</span> n<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">if</span><span class="token punctuation">(</span>n <span class="token operator">&lt;</span> <span class="token number">2</span><span class="token punctuation">)</span>
            <span class="token keyword">return</span> n<span class="token punctuation">;</span>
        <span class="token keyword">int</span> f <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">,</span> g <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>
        <span class="token keyword">int</span> result <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>
        
        <span class="token comment">// 迭代</span>
        <span class="token keyword">for</span><span class="token punctuation">(</span><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> n<span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
            result <span class="token operator">=</span> f <span class="token operator">+</span> g<span class="token punctuation">;</span>
            f <span class="token operator">=</span> g<span class="token punctuation">;</span>
            g <span class="token operator">=</span> result<span class="token punctuation">;</span>
        <span class="token punctuation">}</span>
        <span class="token keyword">return</span> result<span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token comment">// 利用数组，空间换时间</span>
<span class="token keyword">int</span> <span class="token function">Fibonacci</span><span class="token punctuation">(</span>n<span class="token punctuation">)</span><span class="token punctuation">{</span>
    <span class="token comment">// 注意溢出</span>
 <span class="token keyword">int</span> arr<span class="token punctuation">[</span><span class="token number">100</span><span class="token punctuation">]</span><span class="token operator">=</span><span class="token punctuation">{</span><span class="token number">0</span><span class="token punctuation">,</span><span class="token number">1</span><span class="token punctuation">,</span><span class="token number">1</span><span class="token punctuation">}</span>
 
 <span class="token comment">// 叠加，结果存放在数组中</span>
 <span class="token keyword">for</span><span class="token punctuation">(</span>let i<span class="token operator">=</span><span class="token number">3</span><span class="token punctuation">;</span>i<span class="token operator">&lt;=</span>n<span class="token punctuation">;</span>i<span class="token operator">++</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
  arr<span class="token punctuation">[</span>i<span class="token punctuation">]</span><span class="token operator">=</span>arr<span class="token punctuation">[</span>i<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token operator">+</span>arr<span class="token punctuation">[</span>i<span class="token operator">-</span><span class="token number">2</span><span class="token punctuation">]</span>
 <span class="token punctuation">}</span>
 <span class="token keyword">return</span> arr<span class="token punctuation">[</span>n<span class="token punctuation">]</span>
<span class="token punctuation">}</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>必须注意递归模型不能是循环定义的，满足条件：</p><ul><li>递归表达式（递归体）</li><li>边界条件（递归出口），即：算法结束条件</li></ul><p>递归的精髓在于是否能够将原来的问题转化为属性相同但规模较小的问题。有点类似实现目标过程中，将大目标转化为小目标（1亿....）来解决,噗呲啊哈哈哈</p><p><strong>递归次数过多容易造成栈溢出，效率不高的主要原因是递归调用过程中包含很多重复的计算</strong></p><h2 id="队列的应用" tabindex="-1"><a class="header-anchor" href="#队列的应用" aria-hidden="true">#</a> 队列的应用</h2><ul><li>层次遍历</li></ul><blockquote><p>例如：二叉树的遍历</p></blockquote><ul><li>计算机系统</li></ul><p>队列在计算机系统中的应用非常广泛，作用：</p><ul><li>解决主机和外部设备之间速度不匹配的问题（例如：内存和打印机）</li><li>解决由多用户引起的资源竞争问题（例如：操作系统中的进程调度...）</li></ul><p>其实，队列在计算机系统的中应用， 在看完操作系统那本书后，就会很好理解，建议学到这里，也去翻翻操作系统，汤晓丹那本很经典哟...</p><h2 id="特殊矩阵的压缩存储" tabindex="-1"><a class="header-anchor" href="#特殊矩阵的压缩存储" aria-hidden="true">#</a> 特殊矩阵的压缩存储</h2><blockquote><p>这部分知识我个人觉得以了解为主，复习、学习的时候还是要以前面的部分为主！</p></blockquote><p>矩阵在<code>计算机图形学</code>、<code>工程计算</code>中占有举足轻重的地位。</p><h3 id="数组的定义" tabindex="-1"><a class="header-anchor" href="#数组的定义" aria-hidden="true">#</a> 数组的定义</h3><p><code>数组</code>： 由n(n≥1)个相同类型的数据元素构成的有限序列。</p><p>每个数据元素称为一个数组元素，同时每个元素受n个线性关系的约束，<strong>每个元素在n个线性关系中的序号称为元素的<code>下标</code></strong>，称为该数组为n的数组。</p><p>数组和线性表的关系：</p><ul><li>数组是线性表的推广。</li><li>数组一旦被定义，维数和维界就不再改变。</li><li>除了结构的初始化和销毁外，数组只会有存取元素和修改元素的操作。</li></ul><p>一维数组可以看做是一个线性表</p><p>二维数组可以看做元素是线性表的线性表</p><p>....</p><h3 id="矩阵的压缩存储" tabindex="-1"><a class="header-anchor" href="#矩阵的压缩存储" aria-hidden="true">#</a> 矩阵的压缩存储</h3><p><code>压缩存储</code>：多个值相同的元素只分配一个存储空间，对零元素不分配存储空间----&gt;节省存储空间。</p><p><code>特殊矩阵</code>：具有很多相同矩阵元素或零元素，并且这些相同矩阵元素或零元素的分布有一定规律性的矩阵。</p><ul><li>对称矩阵</li><li>上、下三角矩阵</li><li>对角矩阵（带状矩阵）</li><li>....</li></ul><p>这里如果学过线性代数这本书，其实也就很好理解（赶紧去把数学知识捡起来鸭，噗呲哈哈啊哈）</p><p><code>稀疏矩阵</code>：矩阵元素个数s相对于矩阵中非零元素的个数t来说非常多、差距非常大，即<code>s&gt;&gt;t的矩阵</code>可以叫<code>稀疏矩阵</code></p><p>注意：</p><ul><li>常规方法来存储稀疏矩阵，会想当浪费存储空间，所以稀疏矩阵只需要存储非零元素</li><li>通常非零元素的分布是没有规律的，除了存储非零元素外，还需要存储元素所在位置的行和列</li><li>寻相互存储三元组 <code>&lt;行标，列表，值&gt;</code></li></ul><figure><img src="`+i+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>三元组的结点存储了行标(row)、列表(col)、值(value)三种信息，是主要用来存储稀疏矩阵的一种数据结构。</p><p><strong>注意：矩阵压缩存储的目的就是为了节省空间，已经存过的就不存或者少存（经典想法）</strong></p>',49);function v(m,b){const s=p("Mermaid");return e(),t("div",null,[r,d,o(s,{id:"mermaid-8",code:"eJzLzcxLyU0s4FJQKMrPL9F4tqAjLPjljPlPO6a/WLj0aWurJlAGBEAyz2e1PN015fmUFXBBiEpM8WdTNzzf3QISXzfryc5OuPjz+StfztgKEu/rfr5n5dO1M542AXUBAD19QTI="}),k])}const g=a(u,[["render",v],["__file","stack-vs-queue.html.vue"]]);export{g as default};
